/**
 * Bot Router — platform module
 *
 * AUTO-GENERATED by Phoenix VCS
 * Routes commands to registered bots with mutation safety.
 */

export type CommandHandler = (args: string) => { result: string; mutating: boolean };

export interface Bot {
  name: string;
  commands: Map<string, CommandHandler>;
}

export interface CommandResult {
  bot: string;
  command: string;
  result: string;
  mutating: boolean;
  needsConfirmation: boolean;
  intent?: string;
}

export class BotRouter {
  private bots: Map<string, Bot> = new Map();

  constructor() {
    // Register built-in commands
    const builtinBot: Bot = {
      name: '_system',
      commands: new Map<string, CommandHandler>([
        ['help', () => ({
          result: `Available bots: ${Array.from(this.bots.keys()).join(', ')}`,
          mutating: false,
        })],
        ['commands', () => {
          const allCommands: string[] = [];
          for (const [botName, bot] of this.bots.entries()) {
            for (const cmd of bot.commands.keys()) {
              allCommands.push(`${botName}:${cmd}`);
            }
          }
          return { result: allCommands.join(', '), mutating: false };
        }],
        ['version', () => ({
          result: 'Phoenix Bot Router v1.0.0',
          mutating: false,
        })],
      ]),
    };
    this.bots.set('_system', builtinBot);
  }

  registerBot(bot: Bot): void {
    this.bots.set(bot.name, bot);
  }

  routeCommand(input: string): CommandResult {
    // Parse input: "botname:command args" or "command args" (for system)
    const colonIndex = input.indexOf(':');
    let botName: string;
    let rest: string;

    if (colonIndex >= 0) {
      botName = input.slice(0, colonIndex);
      rest = input.slice(colonIndex + 1);
    } else {
      botName = '_system';
      rest = input;
    }

    const spaceIndex = rest.indexOf(' ');
    const command = spaceIndex >= 0 ? rest.slice(0, spaceIndex) : rest;
    const args = spaceIndex >= 0 ? rest.slice(spaceIndex + 1) : '';

    const bot = this.bots.get(botName);
    if (!bot) {
      return {
        bot: botName,
        command,
        result: `Unknown bot: ${botName}`,
        mutating: false,
        needsConfirmation: false,
      };
    }

    const handler = bot.commands.get(command);
    if (!handler) {
      return {
        bot: botName,
        command,
        result: `Unknown command: ${command}`,
        mutating: false,
        needsConfirmation: false,
      };
    }

    const { result, mutating } = handler(args);

    if (mutating) {
      return {
        bot: botName,
        command,
        result,
        mutating: true,
        needsConfirmation: true,
        intent: `${botName}:${command} ${args}`.trim(),
      };
    }

    return {
      bot: botName,
      command,
      result,
      mutating: false,
      needsConfirmation: false,
    };
  }
}

export function createBotRouter(): BotRouter {
  return new BotRouter();
}

